@dataclass
class ResidentPattern:
    """Per-user fitted mobility pattern statistics derived from training data."""
    home_poi: Optional[str]
    work_poi: Optional[str]
    category_pref: Dict[str, float]
    poi_memory: Dict[str, int]
    start_time_hist: Dict[int, int]
    stop_count_hist: Dict[int, int]
    transition_pmf: Dict[str, Dict[str, float]]
    baseline_mean_stops: float
    mobility_radius_km: float


class ResidentAgent:
    """Resident agent holding observed 2021 trajectories and fitted pattern statistics."""

    def __init__(self, user_id: str, observed_2021: Dict[date, Trajectory]) -> None:
        require(isinstance(user_id, str) and user_id.strip(), "Invalid user_id")
        require(isinstance(observed_2021, dict), "observed_2021 must be a dict")
        self.user_id = user_id
        self.observed_2021 = observed_2021

        # Optional: restrict context for Pattern/Motivation to training-only days to avoid holdout leakage.
        self.available_training_days: Optional[Dict[date, Trajectory]] = None

        self.pattern: Optional[ResidentPattern] = None
        self.category_awareness: Dict[str, float] = {}

        # Cache: cutoff_day_ordinal -> ResidentPattern (LRU-ish bounded).
        self._pattern_cache: "OrderedDict[int, ResidentPattern]" = OrderedDict()
        self._pattern_cache_maxsize = 64

    def clear_pattern_cache(self) -> None:
        """
        Clear any cached per-cutoff Patterns for this agent.

        This is important for calibration loops: caches must not persist across parameter proposals
        because they can hide behavioral changes or cause cross-iteration contamination.
        """
        self._pattern_cache.clear()
        self.pattern = None

    def fit_pattern_from_training(
        self,
        train_days: Dict[date, Trajectory],
        env: POIEnvironment,
        topk_poi_memory: int = 50,
    ) -> None:
        """Fit the agent's Pattern using the provided (2021-only) training days."""
        require(len(train_days) > 0, f"User {self.user_id}: cannot fit pattern from empty training set")

        home_counts: Dict[str, int] = {}
        work_counts: Dict[str, int] = {}
        last_poi_counts: Dict[str, int] = {}

        cat_counts: Dict[str, int] = {}
        poi_counts: Dict[str, int] = {}
        start_hist: Dict[int, int] = {}
        stop_hist: Dict[int, int] = {}
        trans_counts: Dict[str, Dict[str, int]] = {}

        total_stops = 0
        total_days = 0

        for tr in train_days.values():
            if len(tr.visits) == 0:
                continue
            total_days += 1
            total_stops += len(tr.visits)
            stop_hist[len(tr.visits)] = stop_hist.get(len(tr.visits), 0) + 1
            start_hist[tr.visits[0].time_min] = start_hist.get(tr.visits[0].time_min, 0) + 1

            last_poi_counts[tr.visits[-1].poi_token] = last_poi_counts.get(tr.visits[-1].poi_token, 0) + 1

            for v in tr.visits:
                cat_counts[v.category] = cat_counts.get(v.category, 0) + 1
                poi_counts[v.poi_token] = poi_counts.get(v.poi_token, 0) + 1
                if v.poi_token.startswith("Home#"):
                    home_counts[v.poi_token] = home_counts.get(v.poi_token, 0) + 1
                if v.poi_token.startswith("Office#"):
                    work_counts[v.poi_token] = work_counts.get(v.poi_token, 0) + 1

            for i in range(len(tr.visits) - 1):
                c0 = tr.visits[i].category
                c1 = tr.visits[i + 1].category
                trans_counts.setdefault(c0, {})
                trans_counts[c0][c1] = trans_counts[c0].get(c1, 0) + 1

        require(total_days > 0, f"User {self.user_id}: no non-empty training trajectories")

        home_poi = max(home_counts.items(), key=lambda kv: kv[1])[0] if home_counts else None
        work_poi = max(work_counts.items(), key=lambda kv: kv[1])[0] if work_counts else None
        if home_poi is None:
            home_poi = max(last_poi_counts.items(), key=lambda kv: kv[1])[0] if last_poi_counts else None

        cat_total = sum(cat_counts.values())
        category_pref = {c: cnt / cat_total for c, cnt in cat_counts.items()} if cat_total > 0 else {}

        poi_sorted = sorted(poi_counts.items(), key=lambda kv: (-kv[1], kv[0]))
        poi_memory = dict(poi_sorted[:topk_poi_memory])

        transition_pmf: Dict[str, Dict[str, float]] = {}
        all_cats = set(cat_counts.keys())
        for c0, nexts in trans_counts.items():
            denom = 0.0
            pmf: Dict[str, float] = {}
            for c1 in all_cats:
                val = nexts.get(c1, 0) + 1
                pmf[c1] = float(val)
                denom += val
            if denom <= 0:
                continue
            transition_pmf[c0] = {k: v / denom for k, v in pmf.items()}

        baseline_mean_stops = total_stops / max(1, total_days)

        mobility_radius_km = 5.0
        if home_poi is not None:
            dists_from_home: List[float] = []
            for poi_token in poi_counts.keys():
                if poi_token == home_poi:
                    continue
                d = env.distance_km(home_poi, poi_token)
                if d is not None:
                    dists_from_home.append(d)
            if dists_from_home:
                dists_from_home.sort()
                n = len(dists_from_home)
                if n % 2 == 1:
                    mobility_radius_km = dists_from_home[n // 2]
                else:
                    mobility_radius_km = (dists_from_home[n // 2 - 1] + dists_from_home[n // 2]) / 2.0
                mobility_radius_km = max(0.5, min(50.0, mobility_radius_km))

        self.pattern = ResidentPattern(
            home_poi=home_poi,
            work_poi=work_poi,
            category_pref=category_pref,
            poi_memory=poi_memory,
            start_time_hist=start_hist,
            stop_count_hist=stop_hist,
            transition_pmf=transition_pmf,
            baseline_mean_stops=baseline_mean_stops,
            mobility_radius_km=mobility_radius_km,
        )

    def ensure_pattern_upto(self, cutoff_day: date, env: POIEnvironment) -> None:
        """
        Ensure self.pattern is fit using only days strictly prior to cutoff_day.

        Uses agent.available_training_days if set; otherwise falls back to agent.observed_2021.

        If no prior days exist (possible for earliest training dates), falls back to fitting on all
        available context to avoid runtime failure; this fallback is not expected for validation
        targets due to the >=7 prior-day eligibility constraint.
        """
        require(isinstance(cutoff_day, date), "cutoff_day must be a datetime.date")
        cutoff_key = cutoff_day.toordinal()

        if cutoff_key in self._pattern_cache:
            pat = self._pattern_cache[cutoff_key]
            self._pattern_cache.move_to_end(cutoff_key)
            self.pattern = pat
            return

        source = self.available_training_days if self.available_training_days is not None else self.observed_2021
        prior = {d: tr for d, tr in source.items() if d < cutoff_day and is_2021(d)}
        if not prior:
            prior = dict(source)

        self.fit_pattern_from_training(prior, env)

        require(self.pattern is not None, "Pattern fitting produced None unexpectedly")
        self._pattern_cache[cutoff_key] = self.pattern
        self._pattern_cache.move_to_end(cutoff_key)
        while len(self._pattern_cache) > self._pattern_cache_maxsize:
            self._pattern_cache.popitem(last=False)

    def decay_awareness(self, decay: float = 0.5) -> None:
        """Decay transient awareness values in-place."""
        require(0.0 < decay <= 1.0, "decay must be in (0,1]")
        for k in list(self.category_awareness.keys()):
            self.category_awareness[k] *= decay
            if self.category_awareness[k] < 1e-6:
                del self.category_awareness[k]

    def reset_awareness(self) -> None:
        """Reset transient encounter-driven awareness (used to avoid cross-rollout contamination)."""
        self.category_awareness = {}


# -----------------------
# Simulator parameters
# -----------------------
@dataclass
class SimulatorParameters:
    """Global parameters calibrated across all agents."""
    alpha_dist: float
    alpha_pref: float
    alpha_anchor: float
    routine_strength: float
    exploration_rate: float
    travel_time_scale: float
    return_home_bias: float
    social_influence_strength: float
    global_mobility_noise_sigma: float
    time_of_day_category_profile: Dict[int, Dict[str, float]]
    dwell_time_mean_by_category: Dict[str, float]


def clip(v: float, lo: float, hi: float) -> float:
    """Clip v into [lo, hi]."""
    return max(lo, min(hi, v))


def motivation_delta(motivation: Optional[Dict[str, float]]) -> float:
    """Extract exploration delta from a motivation dict."""
    if not motivation:
        return 0.0
    return float(motivation.get("exploration_delta", 0.0))


def reset_all_awareness(agents: Dict[str, ResidentAgent]) -> None:
    """Reset transient awareness for all agents."""
    for a in agents.values():
        a.reset_awareness()


def clear_all_pattern_caches(agents: Dict[str, ResidentAgent]) -> None:
    """Clear pattern caches and current patterns for all agents."""
    for a in agents.values():
        a.clear_pattern_cache()


# -----------------------
# Evaluator
# -----------------------
class Evaluator:
    """Compute required validation metrics comparing simulated vs ground truth trajectories."""

    def __init__(self, env: POIEnvironment, coarse_map: Dict[str, str]) -> None:
        self.env = env
        self.coarse_map = coarse_map

    def _collect_category_counts(self, trajs: Iterable[Trajectory]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for tr in trajs:
            for v in tr.visits:
                coarse = to_coarse_category(v.category, self.coarse_map)
                counts[coarse] = counts.get(coarse, 0) + 1
        return counts

    def _category_share_dist(self, counts: Dict[str, int]) -> Dict[str, float]:
        total = sum(counts.values())
        if total <= 0:
            return {}
        return {k: v / total for k, v in counts.items()}

    def _collect_stop_counts(self, trajs: Iterable[Trajectory]) -> List[int]:
        return [len(tr.visits) for tr in trajs]

    def _collect_tod_hist(self, trajs: Iterable[Trajectory]) -> List[float]:
        hist = [0.0] * TOD_NUM_BINS
        total = 0
        for tr in trajs:
            for v in tr.visits:
                b = int(v.time_min // TOD_BIN_MINUTES)
                b = max(0, min(TOD_NUM_BINS - 1, b))
                hist[b] += 1.0
                total += 1
        if total == 0:
            return [1.0 / TOD_NUM_BINS] * TOD_NUM_BINS
        return [x / total for x in hist]

    def _topk_pois(self, trajs: Iterable[Trajectory], k: int) -> List[str]:
        counts: Dict[str, int] = {}
        for tr in trajs:
            for v in tr.visits:
                counts[v.poi_token] = counts.get(v.poi_token, 0) + 1
        items = sorted(counts.items(), key=lambda kv: (-kv[1], kv[0]))
        return [p for p, _ in items[:k]]

    def _collect_transitions(self, trajs: Iterable[Trajectory]) -> Dict[Tuple[str, str], int]:
        trans: Dict[Tuple[str, str], int] = {}
        for tr in trajs:
            cats = [to_coarse_category(v.category, self.coarse_map) for v in tr.visits]
            for i in range(len(cats) - 1):
                key = (cats[i], cats[i + 1])
                trans[key] = trans.get(key, 0) + 1
        return trans

    def _transition_jsd(self, gt: Dict[Tuple[str, str], int], sim: Dict[Tuple[str, str], int]) -> float:
        keys = sorted(set(gt.keys()) | set(sim.keys()))
        if not keys:
            return 0.0
        p = [gt.get(k, 0) for k in keys]
        q = [sim.get(k, 0) for k in keys]
        sp = sum(p)
        sq = sum(q)
        if sp == 0:
            p = [1.0 / len(keys)] * len(keys)
        else:
            p = [x / sp for x in p]
        if sq == 0:
            q = [1.0 / len(keys)] * len(keys)
        else:
            q = [x / sq for x in q]
        return jensen_shannon_divergence(p, q)

    def _trip_distances(self, trajs: Iterable[Trajectory]) -> Tuple[List[float], Dict[str, Any]]:
        dists: List[float] = []
        eligible_pairs = 0
        matched_pairs = 0
        for tr in trajs:
            for i in range(len(tr.visits) - 1):
                eligible_pairs += 1
                a = tr.visits[i].poi_token
                b = tr.visits[i + 1].poi_token
                dist = self.env.distance_km(a, b)
                if dist is None:
                    continue
                matched_pairs += 1
                dists.append(dist)
        meta = {
            "eligible_pairs": eligible_pairs,
            "matched_pairs_with_coords": matched_pairs,
            "coord_match_rate": (matched_pairs / eligible_pairs) if eligible_pairs > 0 else None,
        }
        return dists, meta

    def compute_metrics(
        self,
        simulated: List[Trajectory],
        ground_truth: List[Trajectory],
        objective_weights: Dict[str, float],
    ) -> Tuple[Dict[str, float], float, Dict[str, Any]]:
        require(len(ground_truth) > 0, "No ground-truth trajectories provided for metric computation")
        require(len(simulated) > 0, "No simulated trajectories provided for metric computation")

        gt_cat_counts = self._collect_category_counts(ground_truth)
        sim_cat_counts = self._collect_category_counts(simulated)
        gt_share = self._category_share_dist(gt_cat_counts)
        sim_share = self._category_share_dist(sim_cat_counts)
        cats = sorted(set(gt_share.keys()) | set(sim_share.keys()))
        if not cats:
            category_share_mae = 0.0
        else:
            category_share_mae = sum(abs(gt_share.get(c, 0.0) - sim_share.get(c, 0.0)) for c in cats) / len(cats)

        gt_counts = self._collect_stop_counts(ground_truth)
        sim_counts = self._collect_stop_counts(simulated)
        gt_mean = sum(gt_counts) / max(1, len(gt_counts))
        sim_mean = sum(sim_counts) / max(1, len(sim_counts))
        stop_count_abs_mean_error = abs(gt_mean - sim_mean)

        max_count = max(max(gt_counts, default=0), max(sim_counts, default=0))
        if max_count <= 0:
            stop_count_kl = 0.0
        else:
            support = list(range(1, max_count + 1))
            eps = 1e-6
            gt_hist = {k: eps for k in support}
            sim_hist = {k: eps for k in support}
            for c in gt_counts:
                if c in gt_hist:
                    gt_hist[c] += 1.0
            for c in sim_counts:
                if c in sim_hist:
                    sim_hist[c] += 1.0
            p = [gt_hist[k] for k in support]
            q = [sim_hist[k] for k in support]
            stop_count_kl = kl_divergence(p, q)

        gt_tod = self._collect_tod_hist(ground_truth)
        sim_tod = self._collect_tod_hist(simulated)
        tod_jsd_avg = jensen_shannon_divergence(gt_tod, sim_tod)

        gt_topk = self._topk_pois(ground_truth, TOPK_POI_RECALL_K)
        gt_k_eff = max(1, min(TOPK_POI_RECALL_K, len(gt_topk)))
        sim_poi_set = set(v.poi_token for tr in simulated for v in tr.visits)
        hit = sum(1 for p in gt_topk[:gt_k_eff] if p in sim_poi_set)
        topk_poi_recall = hit / gt_k_eff

        gt_trans = self._collect_transitions(ground_truth)
        sim_trans = self._collect_transitions(simulated)
        transition_divergence = self._transition_jsd(gt_trans, sim_trans)

        gt_dists, gt_dist_meta = self._trip_distances(ground_truth)
        sim_dists, sim_dist_meta = self._trip_distances(simulated)
        trip_distance_wasserstein = wasserstein_1d(gt_dists, sim_dists)

        metrics = {
            "category_share_mae": float(category_share_mae),
            "stop_count_abs_mean_error": float(stop_count_abs_mean_error),
            "stop_count_kl": float(stop_count_kl),
            "tod_jsd_avg": float(tod_jsd_avg),
            "topk_poi_recall": float(topk_poi_recall),
            "transition_divergence": float(transition_divergence),
            "trip_distance_wasserstein": float(trip_distance_wasserstein),
        }

        obj = 0.0
        for k, w in objective_weights.items():
            if k == "topk_poi_recall":
                obj += w * (1.0 - metrics[k])
            else:
                obj += w * metrics[k]

        meta = {
            "gt_trip_distance_meta": gt_dist_meta,
            "sim_trip_distance_meta": sim_dist_meta,
            "gt_num_days": len(ground_truth),
            "sim_num_days": len(simulated),
        }
        return metrics, float(obj), meta


# -----------------------
# Simulator
# -----------------------
class MobilitySimulator:
    """Generates daily trajectories for agents based on fitted patterns and global parameters."""

    def __init__(
        self,
        env: POIEnvironment,
        agents: Dict[str, ResidentAgent],
        base_parameters: SimulatorParameters,
        seed: int,
    ) -> None:
        require(isinstance(agents, dict) and len(agents) > 0, "No agents provided")
        self.env = env
        self.agents = agents
        self.parameters = base_parameters
        self.seed = int(seed)
        self.rng = random.Random(self.seed)

        # Empirical prior for missing-coordinate distance fallback.
        self.fallback_distance_samples_km: List[float] = []
        self.fallback_distance_median_km: float = 3.0

    def set_parameters(self, params: SimulatorParameters) -> None:
        """Set simulator parameters."""
        self.parameters = params

    def _day_exogenous(self, d: date) -> Dict[str, int]:
        """Compute simple exogenous features from a date."""
        return {"day_of_week": d.weekday(), "month": d.month}

    def _compute_motivation(self, agent: ResidentAgent, target_day: date) -> Dict[str, float]:
        """
        Compute Motivation from the past 7 observed days strictly prior to target_day.

        Blueprint semantics: only compute non-neutral motivation when >=7 prior observed days exist.
        To avoid holdout leakage, if agent.available_training_days is set, only those days are used.
        """
        require(agent.pattern is not None, "Agent pattern must be fit before computing motivation")

        source = agent.available_training_days if agent.available_training_days is not None else agent.observed_2021
        prior_days = sorted([d for d in source.keys() if d < target_day and is_2021(d)])
        if len(prior_days) < 7:
            return {"stop_multiplier": 1.0, "routine_delta": 0.0, "exploration_delta": 0.0, "return_home_delta": 0.0}

        window = prior_days[-7:]
        trajs = [source[d] for d in window if d in source]
        if len(trajs) < 7:
            return {"stop_multiplier": 1.0, "routine_delta": 0.0, "exploration_delta": 0.0, "return_home_delta": 0.0}

        avg_stops = sum(len(tr.visits) for tr in trajs) / float(len(trajs))
        baseline = max(1e-6, agent.pattern.baseline_mean_stops)
        ratio = avg_stops / baseline

        stop_multiplier = clip(0.85 + 0.3 * ratio, 0.6, 1.4)
        routine_delta = clip((1.0 - ratio) * 0.2, -0.15, 0.25)
        exploration_delta = clip((ratio - 1.0) * 0.15, -0.2, 0.2)
        return_home_delta = clip((1.0 - ratio) * 0.25, -0.2, 0.35)

        return {
            "stop_multiplier": float(stop_multiplier),
            "routine_delta": float(routine_delta),
            "exploration_delta": float(exploration_delta),
            "return_home_delta": float(return_home_delta),
        }

    def _sample_start_time(self, agent: ResidentAgent) -> int:
        """Sample a per-user start time from the empirical first-visit histogram."""
        require(agent.pattern is not None, "Agent pattern must be fitted")
        hist = agent.pattern.start_time_hist
        if not hist:
            return int(8 * 60)
        total = sum(hist.values())
        r = self.rng.random() * total
        acc = 0.0
        for tmin, cnt in sorted(hist.items()):
            acc += cnt
            if r <= acc:
                return int(clip(tmin, 0, 1439))
        return int(clip(sorted(hist.keys())[0], 0, 1439))

    def _tilted_stop_pmf(
        self, hist: Dict[int, int], feasible_counts: List[int], target_mean: float
    ) -> Dict[int, float]:
        """Exponentially tilt an empirical stop-count histogram to match a target mean (approximately)."""
        base_weights = {c: float(hist.get(c, 0)) for c in feasible_counts}
        total = sum(base_weights.values())
        if total <= 0:
            return {c: 1.0 for c in feasible_counts}
        base_mean = sum(c * w for c, w in base_weights.items()) / total

        target_mean = clip(target_mean, min(feasible_counts), max(feasible_counts))
        if abs(target_mean - base_mean) < 1e-6:
            return base_weights

        def mean_for_beta(beta: float) -> float:
            num = 0.0
            den = 0.0
            for c, w in base_weights.items():
                ww = w * math.exp(beta * c)
                num += ww * c
                den += ww
            if den <= 0:
                return base_mean
            return num / den

        lo, hi = (-2.0, 2.0)
        m_lo = mean_for_beta(lo)
        m_hi = mean_for_beta(hi)
        if not (min(m_lo, m_hi) <= target_mean <= max(m_lo, m_hi)):
            beta = hi if target_mean > base_mean else lo
        else:
            for _ in range(30):
                mid = 0.5 * (lo + hi)
                m_mid = mean_for_beta(mid)
                if m_mid < target_mean:
                    lo = mid
                else:
                    hi = mid
            beta = 0.5 * (lo + hi)

        tilted = {c: base_weights[c] * math.exp(beta * c) for c in feasible_counts}
        return tilted

    def _sample_stop_count(self, agent: ResidentAgent, motivation: Dict[str, float], start_time: int) -> int:
        """
        Sample stop count from a per-user histogram, modulated via exponential tilting.

        Also conditions on a simple feasibility bound given start_time and a minimum per-step gap.
        """
        require(agent.pattern is not None, "Agent pattern must be fitted")
        hist = agent.pattern.stop_count_hist
        mult = clip(float(motivation.get("stop_multiplier", 1.0)), 0.6, 1.4)

        min_gap = 5
        max_feasible = max(1, 1 + (1439 - int(clip(start_time, 0, 1439))) // min_gap)

        if not hist:
            base = 4
            return int(clip(round(base * mult), 1, max_feasible))

        counts = sorted([c for c in hist.keys() if 1 <= c <= max_feasible])
        if not counts:
            return 1

        base_total = sum(float(hist[c]) for c in counts)
        base_mean = sum(c * float(hist[c]) for c in counts) / max(1e-9, base_total)
        target_mean = base_mean * mult

        pmf_unnorm = self._tilted_stop_pmf(hist, counts, target_mean)
        choice = sample_from_pmf(self.rng, pmf_unnorm)
        return int(clip(int(choice), 1, max_feasible))

    def _category_time_profile(self, tmin: int) -> Dict[str, float]:
        """Return global category weights for the current time-of-day bin."""
        b = int(tmin // TOD_BIN_MINUTES)
        b = max(0, min(TOD_NUM_BINS - 1, b))
        prof = self.parameters.time_of_day_category_profile.get(b)
        return prof or {}

    def _blend_profiles(self, a: Dict[str, float], b: Dict[str, float], w_a: float) -> Dict[str, float]:
        """Blend two nonnegative profiles and renormalize."""
        w_a = clip(float(w_a), 0.0, 1.0)
        w_b = 1.0 - w_a
        keys = set(a.keys()) | set(b.keys())
        out: Dict[str, float] = {}
        total = 0.0
        for k in keys:
            v = w_a * float(a.get(k, 0.0)) + w_b * float(b.get(k, 0.0))
            if v > 0:
                out[k] = v
                total += v
        if total <= 0:
            return {}
        return {k: v / total for k, v in out.items()}

    def _choose_next_category(
        self,
        agent: ResidentAgent,
        current_category: Optional[str],
        tmin: int,
        exo: Dict[str, int],
        motivation: Dict[str, float],
    ) -> str:
        """Choose next activity category as a mix of transition model and time-of-day profile."""
        require(agent.pattern is not None, "Agent pattern must be fitted")
        routine_strength = clip(self.parameters.routine_strength + motivation.get("routine_delta", 0.0), 0.0, 1.0)

        trans: Dict[str, float] = {}
        if current_category is not None:
            trans = agent.pattern.transition_pmf.get(current_category, {})

        # Blend global time profile with per-user category preference to reduce global dominance.
        prof_global = self._category_time_profile(tmin)
        prof_user = agent.pattern.category_pref or {}
        prof = self._blend_profiles(prof_global, prof_user, w_a=0.7) if (prof_global or prof_user) else {}

        if not trans and not prof:
            base = agent.pattern.category_pref or {"Other": 1.0}
            return sample_from_pmf(self.rng, base)
        if not trans:
            return sample_from_pmf(self.rng, prof)
        if not prof:
            return sample_from_pmf(self.rng, trans)

        cats = sorted(set(trans.keys()) | set(prof.keys()))
        eps = 1e-9
        logw: List[float] = []
        for c in cats:
            p_trans = trans.get(c, 0.0) + eps
            p_prof = prof.get(c, 0.0) + eps
            p_mix = routine_strength * p_trans + (1.0 - routine_strength) * p_prof

            if exo["day_of_week"] in (5, 6) and c.lower().startswith("office"):
                p_mix *= 0.5

            coarse = to_coarse_category(c, self.env.coarse_category_map)
            aw = agent.category_awareness.get(c, agent.category_awareness.get(coarse, 0.0))
            p_mix *= (1.0 + self.parameters.social_influence_strength * aw)

            logw.append(math.log(p_mix))

        pmf = stable_softmax(logw)
        r = self.rng.random()
        acc = 0.0
        for c, p in zip(cats, pmf):
            acc += p
            if r <= acc:
                return c
        return cats[-1]

    def _choose_anchor_poi(self, pat: ResidentPattern, tmin: int) -> Optional[str]:
        """Choose an anchor POI (work during business hours, otherwise home)."""
        if pat.work_poi and 9 * 60 <= tmin <= 17 * 60:
            return pat.work_poi
        return pat.home_poi

    def _sample_fallback_distance_km(self, pat: ResidentPattern) -> float:
        """Sample a fallback distance when coordinates are missing."""
        if self.fallback_distance_samples_km:
            base = self.fallback_distance_samples_km[self.rng.randrange(len(self.fallback_distance_samples_km))]
            scale = pat.mobility_radius_km / max(1e-6, self.fallback_distance_median_km)
            return float(clip(base * scale, 0.1, 120.0))
        return float(clip(pat.mobility_radius_km, 0.1, 50.0))

    def _distance_km_or_fallback(self, pat: ResidentPattern, a: str, b: str) -> float:
        """Return distance in km; sample a distributional fallback if coordinates are missing."""
        d = self.env.distance_km(a, b)
        if d is None:
            return self._sample_fallback_distance_km(pat)
        return float(d)

    def _choose_next_poi(
        self,
        agent: ResidentAgent,
        category: str,
        current_poi: Optional[str],
        tmin: int,
        motivation: Optional[Dict[str, float]] = None,
    ) -> str:
        """Choose the next POI within a category using distance, anchor, memory, and noise utilities."""
        require(agent.pattern is not None, "Agent pattern must be fitted")
        pat = agent.pattern

        mem_in_cat = [p for p in pat.poi_memory.keys() if fine_category_from_poi_token(p) == category]
        anchor = self._choose_anchor_poi(pat, tmin)

        candidates = self.env.candidates_for_category(
            category, k=DEFAULT_CANDIDATE_POOL_SIZE, anchor_poi=anchor, rng=self.rng
        )

        top_pref_in_cat: List[str] = []
        if mem_in_cat:
            top_pref_in_cat = [
                p for p, _ in sorted(
                    ((p, pat.poi_memory.get(p, 0)) for p in mem_in_cat),
                    key=lambda kv: (-kv[1], kv[0]),
                )
            ][:30]

        merged = list(dict.fromkeys(top_pref_in_cat + mem_in_cat + candidates))
        if not merged:
            merged = list(self.env.poi_catalog.keys())

        exploration = clip(self.parameters.exploration_rate + motivation_delta(motivation), 0.0, 1.0)

        if mem_in_cat and self.rng.random() > exploration:
            pool = mem_in_cat[: min(len(mem_in_cat), DEFAULT_CANDIDATE_POOL_SIZE)]
        else:
            pool = merged[: min(len(merged), DEFAULT_CANDIDATE_POOL_SIZE)]

        # Ensure a minimum share of coord-known POIs when possible (improves coord-join coverage for distance eval).
        coord_pool = [p for p in pool if self.env.has_coords(p)]
        if coord_pool:
            min_coord_share = 0.6
            target_coord = int(round(min_coord_share * len(pool)))
            target_coord = min(len(pool), max(0, target_coord))
            if len(coord_pool) < target_coord:
                # Augment from merged to reach target if possible.
                extra = [p for p in merged if p not in pool and self.env.has_coords(p)]
                if extra:
                    add_n = min(target_coord - len(coord_pool), len(extra))
                    pool.extend(extra[:add_n])
                    pool = list(dict.fromkeys(pool))[:DEFAULT_CANDIDATE_POOL_SIZE]

        cur_has = self.env.has_coords(current_poi) if current_poi is not None else False
        anc_has = self.env.has_coords(anchor) if anchor is not None else False

        if cur_has or anc_has:
            reference_poi = current_poi if cur_has else anchor
            pool_with_dist: List[Tuple[float, str]] = []
            pool_without_coords: List[str] = []
            for poi in pool:
                if self.env.has_coords(poi):
                    d = self._distance_km_or_fallback(pat, reference_poi, poi)
                    pool_with_dist.append((d, poi))
                else:
                    pool_without_coords.append(poi)

            pool_with_dist.sort(key=lambda x: x[0])
            near_k = min(150, len(pool_with_dist))
            near_pois = [p for _, p in pool_with_dist[:near_k]]

            explore_k = min(20, len(pool_without_coords))
            if explore_k > 0:
                self.rng.shuffle(pool_without_coords)
                explore_pois = pool_without_coords[:explore_k]
            else:
                explore_pois = []

            pool = list(dict.fromkeys(near_pois + top_pref_in_cat + explore_pois))
            if not pool:
                pool = merged[:DEFAULT_CANDIDATE_POOL_SIZE]

        if len(pool) > DEFAULT_CANDIDATE_POOL_SIZE:
            must_keep: List[str] = []
            if top_pref_in_cat:
                must_keep.extend(top_pref_in_cat[:10])
            if pat.home_poi:
                must_keep.append(pat.home_poi)
            must_keep = list(dict.fromkeys(must_keep))
            must_keep_set = set(must_keep)
            remain = [p for p in pool if p not in must_keep_set]
            fill_count = max(0, min(DEFAULT_CANDIDATE_POOL_SIZE - len(must_keep), len(remain)))
            fill = self.rng.sample(remain, fill_count) if remain and fill_count > 0 else []
            pool = (must_keep + fill)[:DEFAULT_CANDIDATE_POOL_SIZE]

        alpha_dist = clip(self.parameters.alpha_dist, 0.0, 10.0)
        alpha_pref = clip(self.parameters.alpha_pref, 0.0, 10.0)
        alpha_anchor = clip(self.parameters.alpha_anchor, 0.0, 10.0)
        noise_sigma = clip(self.parameters.global_mobility_noise_sigma, 0.0, 5.0)

        norm_radius = max(0.5, pat.mobility_radius_km)

        # Stronger coordinate-known preference to improve coord-match coverage for distance evaluation.
        coord_bonus = 1.0

        util: List[float] = []
        for poi in pool:
            u = 0.0
            cnt = pat.poi_memory.get(poi, 0)
            if cnt > 0:
                u += alpha_pref * math.log(1.0 + cnt)

            if self.env.has_coords(poi):
                u += coord_bonus

            if current_poi is not None:
                dcur = self._distance_km_or_fallback(pat, current_poi, poi)
                u -= alpha_dist * math.log1p(dcur / norm_radius)

            if anchor is not None and not (current_poi is not None and anchor == current_poi):
                danc = self._distance_km_or_fallback(pat, anchor, poi)
                u -= alpha_anchor * math.log1p(danc / norm_radius)

            if noise_sigma > 0:
                u += self.rng.gauss(0.0, noise_sigma)

            util.append(u)

        pmf = stable_softmax(util)
        r = self.rng.random()
        acc = 0.0
        for poi, p in zip(pool, pmf):
            acc += p
            if r <= acc:
                return poi
        return pool[-1]

    def _sample_dwell_minutes(self, category: str) -> int:
        """Sample dwell time using a lognormal distribution parameterized by a category mean."""
        mean = float(self.parameters.dwell_time_mean_by_category.get(category, 45.0))
        mean = clip(mean, 5.0, 240.0)
        sigma = 0.5
        mu = math.log(mean) - 0.5 * sigma * sigma
        x = math.exp(self.rng.gauss(mu, sigma))
        return int(clip(round(x), 5, 240))

    def _travel_minutes(self, from_poi: Optional[str], to_poi: str, pat: Optional[ResidentPattern] = None) -> int:
        """Compute travel minutes using distance * scale with a distributional fallback if coords are missing."""
        if from_poi is None:
            return 0
        d = self.env.distance_km(from_poi, to_poi)
        if d is None:
            d = self._sample_fallback_distance_km(pat) if pat is not None else 3.0
        scale = clip(self.parameters.travel_time_scale, 0.0, 60.0)
        return int(clip(round(scale * float(d)), 0, 180))

    def generate_day(self, agent: ResidentAgent, day: date) -> Trajectory:
        """Generate a day trajectory for an agent and a specific date."""
        # Strict pre-target conditioning for Pattern/Persona.
        agent.ensure_pattern_upto(day, self.env)
        require(agent.pattern is not None, "Agent pattern must be fitted before simulation")
        pat = agent.pattern

        exo = self._day_exogenous(day)
        motivation = self._compute_motivation(agent, day)

        start_time = self._sample_start_time(agent)
        stop_count = self._sample_stop_count(agent, motivation, start_time=start_time)

        current_poi = pat.home_poi
        current_cat = fine_category_from_poi_token(current_poi) if current_poi else None
        t = int(clip(start_time, 0, 1439))

        visits: List[Visit] = []
        recent_pois: List[str] = []

        if current_poi is not None:
            visits.append(Visit(poi_token=current_poi, category=fine_category_from_poi_token(current_poi), time_min=t))
            recent_pois.append(current_poi)

        min_gap = 5

        # Planned remaining steps; we allow early stopping via a hazard.
        remaining_budget = 1439 - t
        remaining_steps = stop_count - len(visits)
        if remaining_steps > 0:
            max_additional = remaining_budget // min_gap
            remaining_steps = min(remaining_steps, max_additional)

        # Time-dependent stopping hazard (return_home_bias acts as strength).
        hazard_bias = clip(self.parameters.return_home_bias + motivation.get("return_home_delta", 0.0), 0.0, 5.0)
        hazard_strength = hazard_bias / (1.0 + hazard_bias)  # maps to [0, ~0.83]

        for _ in range(remaining_steps):
            # Increasing probability to stop as the day gets late and as progress approaches planned stops.
            progress = len(visits) / max(1.0, float(stop_count))
            late = sigmoid((t - 19 * 60) / 90.0)  # ramps up after ~19:00
            p_stop = clip(hazard_strength * late + 0.15 * progress * late, 0.0, 0.95)

            # Avoid immediate termination at day start.
            if len(visits) >= 2 and self.rng.random() < p_stop:
                break

            next_cat = self._choose_next_category(agent, current_cat, t, exo, motivation)
            next_poi = self._choose_next_poi(agent, next_cat, current_poi, t, motivation)

            if recent_pois and next_poi == recent_pois[-1]:
                alt_poi = self._choose_next_poi(agent, next_cat, current_poi, t, motivation)
                if alt_poi != next_poi:
                    next_poi = alt_poi

            dwell = self._sample_dwell_minutes(next_cat)
            travel = self._travel_minutes(current_poi, next_poi, pat)

            t_next = t + max(min_gap, dwell + travel)
            if t_next > 1439:
                break

            visits.append(Visit(poi_token=next_poi, category=next_cat, time_min=int(t_next)))
            recent_pois.append(next_poi)
            recent_pois = recent_pois[-5:]
            current_poi = next_poi
            current_cat = next_cat
            t = int(t_next)

        # Optional return-home at end (still useful if the stopping hazard ended early).
        if pat.home_poi is not None and len(visits) > 0:
            bias = clip(self.parameters.return_home_bias + motivation.get("return_home_delta", 0.0), 0.0, 5.0)
            late = max(0.0, (t - 18 * 60) / (6 * 60))
            p_home = clip(late * (bias / (1.0 + bias)), 0.0, 0.9)
            if self.rng.random() < p_home:
                if visits[-1].poi_token != pat.home_poi and t + min_gap <= 1439:
                    t_home = min(1439, t + min_gap)
                    visits.append(
                        Visit(
                            poi_token=pat.home_poi,
                            category=fine_category_from_poi_token(pat.home_poi),
                            time_min=int(t_home),
                        )
                    )

        if len(visits) == 0:
            any_poi = next(iter(self.env.poi_catalog.keys()))
            visits = [Visit(poi_token=any_poi, category=fine_category_from_poi_token(any_poi), time_min=8 * 60)]

        return Trajectory(user_id=agent.user_id, day=day, visits=visits)

    def rollout(self, target_by_user: Dict[str, Dict[date, Trajectory]]) -> Tuple[Dict[str, List[str]], List[Trajectory]]:
        """
        Roll out simulation for a set of target user-days.

        Note: RNG is reset per rollout to make calibration evaluations comparable and deterministic.
        """
        self.rng = random.Random(self.seed)

        targets: List[Tuple[date, str]] = []
        for uid, dmap in target_by_user.items():
            for d in dmap.keys():
                targets.append((d, uid))
        targets.sort(key=lambda x: (x[0].toordinal(), x[1]))

        simulated: List[Trajectory] = []
        serialized: Dict[str, List[str]] = {uid: [] for uid in target_by_user.keys()}

        idx = 0
        while idx < len(targets):
            day = targets[idx][0]
            day_uids: List[str] = []
            while idx < len(targets) and targets[idx][0] == day:
                day_uids.append(targets[idx][1])
                idx += 1

            day_trajs: List[Trajectory] = []
            for uid in day_uids:
                agent = self.agents.get(uid)
                if agent is None:
                    continue
                tr = self.generate_day(agent, day)
                day_trajs.append(tr)
                simulated.append(tr)
                s = serialize_day_record(day, [(v.poi_token, v.time_min) for v in tr.visits])
                serialized[uid].append(s)

            occupancy: Dict[Tuple[str, int], List[str]] = {}
            for tr in day_trajs:
                for v in tr.visits:
                    b = int(v.time_min // ENCOUNTER_BIN_MINUTES)
                    key = (v.poi_token, b)
                    occupancy.setdefault(key, []).append(tr.user_id)

            for (poi, _b), uids in occupancy.items():
                if len(uids) < 2:
                    continue
                fine_cat = fine_category_from_poi_token(poi)
                coarse = to_coarse_category(fine_cat, self.env.coarse_category_map)
                for uid in set(uids):
                    ag = self.agents.get(uid)
                    if ag is None:
                        continue
                    ag.category_awareness[fine_cat] = ag.category_awareness.get(fine_cat, 0.0) + 0.05
                    ag.category_awareness[coarse] = ag.category_awareness.get(coarse, 0.0) + 0.05

            for uid in day_uids:
                ag = self.agents.get(uid)
                if ag is not None:
                    ag.decay_awareness(decay=0.6)

        return serialized, simulated


