# Calibration
# -----------------------
class BaseCalibrator:
    """Base calibrator interface."""

    def fit(
        self,
        simulator: MobilitySimulator,
        agents: Dict[str, ResidentAgent],
        train_by_user: Dict[str, Dict[date, Trajectory]],
        evaluator: Evaluator,
        objective_weights: Dict[str, float],
    ) -> Tuple[SimulatorParameters, float, List[Dict[str, Any]]]:
        """
        Fit (or evaluate) parameters on the training set.

        Note: For per-target pre-cutoff semantics, we do NOT pre-fit patterns here. Patterns are
        computed per target day via ResidentAgent.ensure_pattern_upto() inside the generator.
        """
        require(len(train_by_user) > 0, "Training dataset is empty")

        for uid, agent in agents.items():
            if uid in train_by_user:
                agent.available_training_days = train_by_user[uid]

        clear_all_pattern_caches(agents)
        reset_all_awareness(agents)

        gt_trajs: List[Trajectory] = []
        for dmap in train_by_user.values():
            gt_trajs.extend(list(dmap.values()))
        require(len(gt_trajs) > 0, "Training dataset has no trajectories")

        _sim_serialized, sim_trajs = simulator.rollout(train_by_user)
        metrics, obj, meta = evaluator.compute_metrics(sim_trajs, gt_trajs, objective_weights)

        cal_log: List[Dict[str, Any]] = [
            {
                "iter": 1,
                "parameters": {
                    "alpha_dist": simulator.parameters.alpha_dist,
                    "alpha_pref": simulator.parameters.alpha_pref,
                    "alpha_anchor": simulator.parameters.alpha_anchor,
                    "routine_strength": simulator.parameters.routine_strength,
                    "exploration_rate": simulator.parameters.exploration_rate,
                    "travel_time_scale": simulator.parameters.travel_time_scale,
                    "return_home_hazard_params": {"bias": simulator.parameters.return_home_bias},
                    "social_influence_strength": simulator.parameters.social_influence_strength,
                    "global_mobility_noise_sigma": simulator.parameters.global_mobility_noise_sigma,
                },
                "objective": float(obj),
                "metrics": metrics,
                "notes": f"default_base_calibrator; meta={meta}",
            }
        ]
        return simulator.parameters, float(obj), cal_log


class RandomSearchCalibrator(BaseCalibrator):
    """Simple deterministic random search calibrator."""

    def __init__(self, n_iter: int, calibration_day_budget: int, seed: int) -> None:
        require(n_iter > 0, "n_iter must be positive")
        require(calibration_day_budget > 0, "calibration_day_budget must be positive")
        self.n_iter = int(n_iter)
        self.calibration_day_budget = int(calibration_day_budget)
        self.seed = int(seed)
        self.rng = random.Random(self.seed)

    def _deterministic_subsample(
        self, train_by_user: Dict[str, Dict[date, Trajectory]], budget: int
    ) -> Dict[str, Dict[date, Trajectory]]:
        """
        Deterministic stratified subsampling across users.

        Uses a round-robin selection across shuffled per-user date lists to reduce variance vs
        selecting a flat global shuffle (which can over-represent heavy users).
        """
        require(budget > 0, "budget must be positive")
        uids = sorted(train_by_user.keys())
        per_user: Dict[str, List[date]] = {}
        for uid in uids:
            dates = sorted(train_by_user[uid].keys(), key=lambda d: d.toordinal())
            if dates:
                self.rng.shuffle(dates)
                per_user[uid] = dates

        out: Dict[str, Dict[date, Trajectory]] = {}
        picked = 0
        idx = 0
        active = [uid for uid in uids if uid in per_user]
        while picked < budget and active:
            uid = active[idx % len(active)]
            if per_user[uid]:
                d = per_user[uid].pop()
                out.setdefault(uid, {})[d] = train_by_user[uid][d]
                picked += 1
            else:
                active.remove(uid)
                if not active:
                    break
                idx = idx % len(active)
                continue
            idx += 1
        return out

    def _propose_params(self, base: SimulatorParameters) -> SimulatorParameters:
        """Propose a new parameter set (slightly narrowed ranges to reduce variance)."""
        alpha_dist = self.rng.uniform(0.0, 10.0)
        alpha_pref = self.rng.uniform(0.0, 10.0)
        routine_strength = self.rng.uniform(0.0, 1.0)
        exploration_rate = self.rng.uniform(0.0, 1.0)

        # Keep within Blueprint bounds [0,60], but avoid extreme values that inflate variance.
        travel_time_scale = self.rng.uniform(0.0, 20.0)

        return_home_bias = self.rng.uniform(0.0, 5.0)
        social_influence_strength = self.rng.uniform(0.0, 2.0)
        global_noise_sigma = self.rng.uniform(0.0, 1.5)

        alpha_anchor = 0.5 * alpha_dist

        return SimulatorParameters(
            alpha_dist=alpha_dist,
            alpha_pref=alpha_pref,
            alpha_anchor=alpha_anchor,
            routine_strength=routine_strength,
            exploration_rate=exploration_rate,
            travel_time_scale=travel_time_scale,
            return_home_bias=return_home_bias,
            social_influence_strength=social_influence_strength,
            global_mobility_noise_sigma=global_noise_sigma,
            time_of_day_category_profile=base.time_of_day_category_profile,
            dwell_time_mean_by_category=base.dwell_time_mean_by_category,
        )

    def fit(
        self,
        simulator: MobilitySimulator,
        agents: Dict[str, ResidentAgent],
        train_by_user: Dict[str, Dict[date, Trajectory]],
        evaluator: Evaluator,
        objective_weights: Dict[str, float],
    ) -> Tuple[SimulatorParameters, float, List[Dict[str, Any]]]:
        require(len(train_by_user) > 0, "Training dataset is empty")
        subsampled_train = self._deterministic_subsample(train_by_user, self.calibration_day_budget)

        # Ensure agents use the correct training-only context during calibration.
        for uid, agent in agents.items():
            if uid in train_by_user:
                agent.available_training_days = train_by_user[uid]

        best_params = simulator.parameters
        best_obj = float("inf")
        cal_log: List[Dict[str, Any]] = []

        gt_trajs: List[Trajectory] = []
        for dmap in subsampled_train.values():
            gt_trajs.extend(list(dmap.values()))
        require(len(gt_trajs) > 0, "Calibration subsample contains no trajectories")

        for it in range(1, self.n_iter + 1):
            params = self._propose_params(simulator.parameters)
            simulator.set_parameters(params)

            # Critical: clear caches between parameter proposals to avoid cross-iteration contamination.
            clear_all_pattern_caches(agents)
            reset_all_awareness(agents)

            _sim_serialized, sim_trajs = simulator.rollout(subsampled_train)
            metrics, obj, meta = evaluator.compute_metrics(sim_trajs, gt_trajs, objective_weights)

            notes = f"subsample_days={sum(len(v) for v in subsampled_train.values())}; meta={meta}"
            cal_log.append(
                {
                    "iter": int(it),
                    "parameters": {
                        "alpha_dist": params.alpha_dist,
                        "alpha_pref": params.alpha_pref,
                        "alpha_anchor": params.alpha_anchor,
                        "routine_strength": params.routine_strength,
                        "exploration_rate": params.exploration_rate,
                        "travel_time_scale": params.travel_time_scale,
                        "return_home_hazard_params": {"bias": params.return_home_bias},
                        "social_influence_strength": params.social_influence_strength,
                        "global_mobility_noise_sigma": params.global_mobility_noise_sigma,
                    },
                    "objective": float(obj),
                    "metrics": metrics,
                    "notes": notes,
                }
            )

            if obj < best_obj:
                best_obj = obj
                best_params = params

            if it == 1 or it % max(1, self.n_iter // 5) == 0:
                log_info(f"calibration iter={it}/{self.n_iter} objective={obj:.6f} best={best_obj:.6f}")

        simulator.set_parameters(best_params)
        return best_params, float(best_obj), cal_log


