# Data ingestion and derived global profiles
# -----------------------
def _load_poi_catalog(poi_json: Any) -> Tuple[Dict[str, Dict[str, Any]], Dict[str, List[str]]]:
    """Parse POI catalog JSON into a POI record dict and a category->POIs index."""
    require(isinstance(poi_json, dict) and len(poi_json) > 0, "POI JSON must be a non-empty object")
    poi_catalog: Dict[str, Dict[str, Any]] = {}
    by_cat: Dict[str, List[str]] = {}
    bad = 0
    for cat, entries in poi_json.items():
        if not isinstance(cat, str) or not isinstance(entries, list):
            continue
        for e in entries:
            if not (isinstance(e, list) and len(e) >= 3):
                bad += 1
                continue
            lat, lon, token = e[0], e[1], e[2]
            if not isinstance(token, str) or "#" not in token:
                bad += 1
                continue
            try:
                latf = float(lat)
                lonf = float(lon)
            except (TypeError, ValueError):
                bad += 1
                continue
            fine_cat = fine_category_from_poi_token(token)
            poi_catalog[token] = {"category": fine_cat, "lat": latf, "lon": lonf}
            by_cat.setdefault(fine_cat, []).append(token)

    require(len(poi_catalog) > 0, "POI catalog parsed empty; check poi_category_192021_longitude_latitude.json format")
    for c in list(by_cat.keys()):
        by_cat[c] = list(dict.fromkeys(by_cat[c]))
    if bad > 0:
        log_info(f"POI catalog: skipped {bad} malformed entries")
    return poi_catalog, by_cat


def _load_catto_map(catto_json: Any) -> Dict[str, str]:
    """Load a fine->coarse category map."""
    if not isinstance(catto_json, dict):
        return {}
    out: Dict[str, str] = {}
    for k, v in catto_json.items():
        if isinstance(k, str) and isinstance(v, str) and k.strip() and v.strip():
            out[k.strip()] = v.strip()
    return out


def _compute_global_time_profile(train_by_user: Dict[str, Dict[date, Trajectory]]) -> Dict[int, Dict[str, float]]:
    """Compute a global time-of-day category profile from training trajectories."""
    counts: Dict[int, Dict[str, int]] = {}
    for dmap in train_by_user.values():
        for tr in dmap.values():
            for v in tr.visits:
                b = int(v.time_min // TOD_BIN_MINUTES)
                b = max(0, min(TOD_NUM_BINS - 1, b))
                counts.setdefault(b, {})
                counts[b][v.category] = counts[b].get(v.category, 0) + 1

    profile: Dict[int, Dict[str, float]] = {}
    for b in range(TOD_NUM_BINS):
        c = counts.get(b, {})
        if not c:
            continue
        s = sum(c.values())
        if s <= 0:
            continue
        profile[b] = {k: v / s for k, v in c.items()}
    return profile


def _compute_dwell_means_by_category(
    train_by_user: Dict[str, Dict[date, Trajectory]],
    env: Optional[POIEnvironment] = None,
    travel_time_scale_guess: float = 1.0,
) -> Dict[str, float]:
    """
    Compute dwell-time mean proxies from inter-visit gaps.

    Important identifiability fix:
    - Inter-visit gaps include both dwell and travel.
    - During generation we add dwell + travel, so estimating dwell directly from gaps would
      double-count travel and push travel_time_scale toward 0.
    - If env is provided, subtract an estimated travel component for coordinate-known legs.
    """
    travel_time_scale_guess = clip(float(travel_time_scale_guess), 0.0, 60.0)

    sums: Dict[str, float] = {}
    cnts: Dict[str, int] = {}
    for dmap in train_by_user.values():
        for tr in dmap.values():
            vs = tr.visits
            for i in range(len(vs) - 1):
                gap = max(1, vs[i + 1].time_min - vs[i].time_min)
                cat = vs[i].category

                dwell_proxy = float(gap)
                if env is not None:
                    dist = env.distance_km(vs[i].poi_token, vs[i + 1].poi_token)
                    if dist is not None and math.isfinite(dist) and dist >= 0.0:
                        travel_est = clip(travel_time_scale_guess * float(dist), 0.0, 180.0)
                        dwell_proxy = max(1.0, dwell_proxy - float(travel_est))

                sums[cat] = sums.get(cat, 0.0) + dwell_proxy
                cnts[cat] = cnts.get(cat, 0) + 1
    out: Dict[str, float] = {}
    for cat, s in sums.items():
        m = s / max(1, cnts.get(cat, 0))
        out[cat] = float(clip(m, 10.0, 180.0))
    return out


def _compute_global_distance_prior(
    train_by_user: Dict[str, Dict[date, Trajectory]],
    env: POIEnvironment,
    max_samples: int = 50000,
) -> Tuple[List[float], float]:
    """
    Build an empirical prior over trip distances from training data (coord-known legs).

    Returns:
      samples_km: list[float] distances
      median_km: median of samples (or default 3.0 if unavailable)
    """
    samples: List[float] = []
    for dmap in train_by_user.values():
        for tr in dmap.values():
            vs = tr.visits
            for i in range(len(vs) - 1):
                if len(samples) >= max_samples:
                    break
                d = env.distance_km(vs[i].poi_token, vs[i + 1].poi_token)
                if d is None:
                    continue
                if math.isfinite(d) and d >= 0.0:
                    samples.append(float(d))
            if len(samples) >= max_samples:
                break
        if len(samples) >= max_samples:
            break

    if not samples:
        return [], 3.0

    samples.sort()
    n = len(samples)
    if n % 2 == 1:
        median = samples[n // 2]
    else:
        median = 0.5 * (samples[n // 2 - 1] + samples[n // 2])
    median = float(clip(median, 0.1, 50.0))
    return samples, median


